        group_stats = {
            'count': data['count'],
            'avg_score': sum(data['scores']) / data['count'] if data['count'] > 0 else 0,
            'max_score': max(data['scores']) if data['count'] > 0 else 0,
            'min_score': min(data['scores']) if data['count'] > 0 else 0
        }

